// VoicePanel.jsx — Voice Q&A interface

import { useState, useEffect, useRef } from "react";
import { askVoiceQuestion } from "../api";

export default function VoicePanel({ sessionId, dashboardContext }) {
  const [listening, setListening] = useState(false);
  const [question, setQuestion] = useState("");
  const [answer, setAnswer] = useState(null);
  const [loading, setLoading] = useState(false);
  const [history, setHistory] = useState([]);
  const [error, setError] = useState("");
  const recognitionRef = useRef(null);
  const bottomRef = useRef(null);

  // Init speech recognition
  useEffect(() => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) return;
    const rec = new SpeechRecognition();
    rec.continuous = false;
    rec.interimResults = false;
    rec.lang = "en-US";
    rec.onresult = (e) => {
      const text = e.results[0][0].transcript;
      setQuestion(text);
      setListening(false);
    };
    rec.onend = () => setListening(false);
    recognitionRef.current = rec;
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [history]);

  const startListening = () => {
    if (!recognitionRef.current) {
      setError("Voice recognition not supported in this browser.");
      return;
    }
    setError("");
    setListening(true);
    recognitionRef.current.start();
  };

  const stopListening = () => {
    recognitionRef.current?.stop();
    setListening(false);
  };

  const handleAsk = async () => {
    if (!question.trim()) return;
    setLoading(true);
    setError("");
    const q = question;
    setQuestion("");
    try {
      const result = await askVoiceQuestion(sessionId, q, dashboardContext);
      const entry = { question: q, answer: result.answer, charts: result.referenced_charts };
      setHistory((prev) => [...prev, entry]);

      // Speak the answer
      if (window.speechSynthesis) {
        const utterance = new SpeechSynthesisUtterance(result.answer);
        utterance.rate = 0.95;
        utterance.pitch = 1;
        window.speechSynthesis.speak(utterance);
      }
    } catch (e) {
      setError("Could not get answer. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.panel}>
      <div style={styles.header}>
        <div style={styles.titleRow}>
          <div style={{ ...styles.micIcon, ...(listening ? styles.micIconActive : {}) }}>
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
              <rect x="4.5" y="1" width="5" height="8" rx="2.5" stroke="currentColor" strokeWidth="1.3"/>
              <path d="M2 7a5 5 0 0010 0M7 12v2" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
            </svg>
          </div>
          <span style={styles.title}>Voice Q&A</span>
        </div>
        <span style={styles.badge}>Ask anything about your dashboard</span>
      </div>

      {/* Chat history */}
      <div style={styles.chatArea}>
        {history.length === 0 && (
          <div style={styles.emptyState}>
            <div style={styles.emptyIcon}>🎤</div>
            <p style={styles.emptyText}>Ask a question about your dashboard using voice or text</p>
            <div style={styles.suggestions}>
              {["Which region has highest sales?", "What's the profit trend?", "Which category performs best?"].map((s) => (
                <button key={s} style={styles.suggestion} onClick={() => setQuestion(s)}>{s}</button>
              ))}
            </div>
          </div>
        )}

        {history.map((item, i) => (
          <div key={i} style={styles.chatItem} className="fade-up">
            {/* Question */}
            <div style={styles.questionBubble}>
              <div style={styles.bubbleIcon}>🙋</div>
              <div style={styles.bubbleText}>{item.question}</div>
            </div>
            {/* Answer */}
            <div style={styles.answerBubble}>
              <div style={styles.bubbleIcon}>🤖</div>
              <div>
                <div style={styles.bubbleText}>{item.answer}</div>
                {item.charts?.length > 0 && (
                  <div style={styles.refCharts}>
                    {item.charts.map((c) => (
                      <span key={c} style={styles.refChip}>{c}</span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        <div ref={bottomRef} />
      </div>

      {/* Error */}
      {error && <div style={styles.error}>{error}</div>}

      {/* Input area */}
      <div style={styles.inputArea}>
        <input
          style={styles.input}
          value={question}
          onChange={(e) => setQuestion(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleAsk()}
          placeholder={listening ? "Listening..." : "Type or use microphone..."}
        />
        {/* Mic button */}
        <button
          style={{ ...styles.iconBtn, ...(listening ? styles.iconBtnActive : {}) }}
          onClick={listening ? stopListening : startListening}
          title={listening ? "Stop listening" : "Start voice input"}
        >
          {listening ? (
            <div style={styles.ripple}>
              <svg width="16" height="16" viewBox="0 0 14 14" fill="none">
                <rect x="4" y="4" width="6" height="6" rx="1" fill="currentColor"/>
              </svg>
            </div>
          ) : (
            <svg width="16" height="16" viewBox="0 0 14 14" fill="none">
              <rect x="4.5" y="1" width="5" height="8" rx="2.5" stroke="currentColor" strokeWidth="1.3"/>
              <path d="M2 7a5 5 0 0010 0M7 12v2" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
            </svg>
          )}
        </button>
        {/* Send button */}
        <button
          style={{ ...styles.sendBtn, ...(loading || !question.trim() ? styles.sendBtnDisabled : {}) }}
          onClick={handleAsk}
          disabled={loading || !question.trim()}
        >
          {loading ? <span style={styles.spinner} /> : (
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M2 8h12M8 2l6 6-6 6" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          )}
        </button>
      </div>
    </div>
  );
}

